import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import styles from './AdminPage.module.css';

// ── Helpers ───────────────────────────────────────────────────────────────────
const DAYS_SHORT = ['ПН', 'ВТ', 'СР', 'ЧТ', 'ПТ', 'СБ', 'ВС'];
const MONTHS = ['ЯНВАРЬ','ФЕВРАЛЬ','МАРТ','АПРЕЛЬ','МАЙ','ИЮНЬ','ИЮЛЬ','АВГУСТ','СЕНТЯБРЬ','ОКТЯБРЬ','НОЯБРЬ','ДЕКАБРЬ'];

function getDaysInMonth(year, month) {
  return new Date(year, month + 1, 0).getDate();
}

function getFirstDayOfMonth(year, month) {
  const d = new Date(year, month, 1).getDay();
  return d === 0 ? 6 : d - 1; // Mon=0
}

// Mock data
const MOCK_LESSONS = [
  { id: 751, start: '09:00', end: '10:30', teacher: 'И.И. Иванов' },
  { id: 749, start: '10:30', end: '12:00', teacher: 'И.И. Иванов' },
  { id: 749, start: '10:30', end: '12:00', teacher: 'И.И. Иванов' },
];

const MOCK_APPLICATIONS = [
  {
    id: 1, date: '04.03.2026',
    name: 'Иванов Иван Иванович', phone: '+7(999)-111-22-33',
    invitedBy: 'Петров А.А.', invitedPhone: '+7(999)-111-22-33',
    status: 'new',
  },
  {
    id: 2, date: '04.03.2026',
    name: 'Сидоров Пётр Петрович', phone: '+7(999)-222-33-44',
    invitedBy: 'Петров А.А.', invitedPhone: '+7(999)-111-22-33',
    status: 'new',
  },
  {
    id: 3, date: '03.03.2026',
    name: 'Кузнецова Анна Игоревна', phone: '+7(999)-555-66-77',
    invitedBy: 'Иванов И.И.', invitedPhone: '+7(999)-888-99-00',
    status: 'new',
  },
];

// ── Component ─────────────────────────────────────────────────────────────────
export default function AdminPage() {
  const { logout } = useAuth();
  const navigate = useNavigate();

  const today = new Date();
  const [currentMonth, setCurrentMonth] = useState(today.getMonth());
  const [currentYear, setCurrentYear] = useState(today.getFullYear());
  const [selectedDay, setSelectedDay] = useState(today.getDate());
  const [activeNav, setActiveNav] = useState('main');
  const [appTab, setAppTab] = useState('new');
  const [comments, setComments] = useState({});
  const [commentOpen, setCommentOpen] = useState(null);
  const [applications, setApplications] = useState(MOCK_APPLICATIONS);

  const daysInMonth = getDaysInMonth(currentYear, currentMonth);
  const firstDay = getFirstDayOfMonth(currentYear, currentMonth);

  function prevMonth() {
    if (currentMonth === 0) { setCurrentMonth(11); setCurrentYear(y => y - 1); }
    else setCurrentMonth(m => m - 1);
  }
  function nextMonth() {
    if (currentMonth === 11) { setCurrentMonth(0); setCurrentYear(y => y + 1); }
    else setCurrentMonth(m => m + 1);
  }

  function handleAccept(id) {
    setApplications(apps => apps.map(a => a.id === id ? { ...a, status: 'accepted' } : a));
    setCommentOpen(null);
  }
  function handleDecline(id) {
    setApplications(apps => apps.map(a => a.id === id ? { ...a, status: 'declined' } : a));
    setCommentOpen(null);
  }

  const newApps = applications.filter(a => a.status === 'new');
  const acceptedApps = applications.filter(a => a.status === 'accepted');
  const displayApps = appTab === 'new' ? newApps : acceptedApps;

  // Group by date
  const grouped = displayApps.reduce((acc, app) => {
    (acc[app.date] = acc[app.date] || []).push(app);
    return acc;
  }, {});

  return (
    <div className={styles.app}>
      {/* ── Sidebar ─────────────────────────────────── */}
      <aside className={styles.sidebar}>
        <div className={styles.sidebarAccent} />
      </aside>

      {/* ── Main ─────────────────────────────────────── */}
      <div className={styles.main}>
        {/* Header */}
        <header className={styles.header}>
          <div className={styles.logo}>
            <img src="/avatar-placeholder.png" alt="" className={styles.avatarImg}
              onError={e => { e.target.style.display='none'; e.target.nextSibling.style.display='flex'; }} />
            <div className={styles.avatarFallback}>🎓</div>
          </div>

          <nav className={styles.headerNav}>
            {['Главная', 'Управление', 'Реферальная система', 'Счета'].map((item) => (
              <button
                key={item}
                className={`${styles.navBtn} ${activeNav === item ? styles.navBtnActive : ''}`}
                onClick={() => setActiveNav(item)}
              >
                {item}
              </button>
            ))}
          </nav>

          <div className={styles.headerRight}>
            <button className={styles.bellBtn}>
              🔔
              <span className={styles.bellDot} />
            </button>
            <span className={styles.userName}>Иван И.</span>
            <button className={styles.logoutBtn} onClick={() => { logout(); navigate('/login'); }} title="Выйти">
              →
            </button>
          </div>
        </header>

        {/* Body */}
        <div className={styles.body}>
          {/* Left: Calendar + Lessons */}
          <div className={styles.leftCol}>
            {/* Calendar */}
            <div className={styles.card}>
              <div className={styles.calHeader}>
                <button className={styles.calNavBtn} onClick={prevMonth}>←</button>
                <span className={styles.calMonthLabel}>{MONTHS[currentMonth]}</span>
                <button className={styles.calNavBtn} onClick={nextMonth}>→</button>
              </div>
              <div className={styles.calGrid}>
                {DAYS_SHORT.map(d => (
                  <span key={d} className={styles.calDayName}>{d}</span>
                ))}
                {Array.from({ length: firstDay }, (_, i) => (
                  <span key={`empty-${i}`} />
                ))}
                {Array.from({ length: daysInMonth }, (_, i) => {
                  const day = i + 1;
                  const isToday = day === today.getDate() && currentMonth === today.getMonth() && currentYear === today.getFullYear();
                  const isSel = day === selectedDay;
                  return (
                    <button
                      key={day}
                      className={`${styles.calDay} ${isToday ? styles.calDayToday : ''} ${isSel ? styles.calDaySelected : ''}`}
                      onClick={() => setSelectedDay(day)}
                    >
                      {day}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Theory lessons */}
            <div className={styles.card}>
              <h3 className={styles.cardTitle}>Теоретические занятия</h3>
              <div className={styles.dateChip}>
                {String(selectedDay).padStart(2,'0')}.{String(currentMonth+1).padStart(2,'0')}.{currentYear}
              </div>
              <div className={styles.lessonList}>
                {MOCK_LESSONS.map((lesson, i) => (
                  <div key={i} className={styles.lessonRow}>
                    <span className={styles.lessonNum}>{lesson.id}</span>
                    <div className={styles.lessonInfo}>
                      <span className={styles.lessonTime}>{lesson.start} - {lesson.end}</span>
                      <span className={styles.lessonTeacher}>Преподаватель: {lesson.teacher}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Right: Applications */}
          <div className={styles.rightCol}>
            <div className={styles.card} style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 0 }}>
              {/* Tabs */}
              <div className={styles.appTabs}>
                <button
                  className={`${styles.appTab} ${appTab === 'new' ? styles.appTabActive : ''}`}
                  onClick={() => setAppTab('new')}
                >
                  Новые заявки {newApps.length > 0 && <span className={styles.badge}>{newApps.length}</span>}
                </button>
                <button
                  className={`${styles.appTab} ${appTab === 'accepted' ? styles.appTabActive : ''}`}
                  onClick={() => setAppTab('accepted')}
                >
                  Принятые
                </button>
              </div>

              <div className={styles.appList}>
                {Object.entries(grouped).length === 0 && (
                  <p className={styles.emptyText}>Нет заявок</p>
                )}
                {Object.entries(grouped).map(([date, apps]) => (
                  <div key={date}>
                    <div className={styles.dateGroup}>{date}</div>
                    {apps.map((app) => (
                      <div key={app.id} className={styles.appCard}>
                        <div className={styles.appName}>{app.name}</div>
                        <div className={styles.appMeta}>
                          <span>📞 {app.phone}</span>
                          <span>👥 пригласил: {app.invitedBy} {app.invitedPhone}</span>
                        </div>
                        {appTab === 'new' && (
                          <div className={styles.appActions}>
                            <button
                              className={styles.commentIconBtn}
                              onClick={() => setCommentOpen(commentOpen === app.id ? null : app.id)}
                              title="Комментарий"
                            >
                              📝
                            </button>
                            <button className={styles.declineBtn} onClick={() => handleDecline(app.id)}>
                              отклонить
                            </button>
                            <button className={styles.acceptBtn} onClick={() => handleAccept(app.id)}>
                              принять
                            </button>
                          </div>
                        )}
                        {commentOpen === app.id && (
                          <div className={styles.commentBox}>
                            <label className={styles.commentLabel}>Комментарий</label>
                            <textarea
                              className={styles.commentInput}
                              placeholder="Введите текст"
                              rows={3}
                              value={comments[app.id] || ''}
                              onChange={e => setComments(c => ({ ...c, [app.id]: e.target.value }))}
                            />
                            <button className={styles.commentDoneBtn}
                              onClick={() => setCommentOpen(null)}>
                              ГОТОВО
                            </button>
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
